PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX pq: <http://www.wikidata.org/prop/qualifier/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT DISTINCT ?player ?playerLabel WHERE {
  # Find teams whose season participated in 2020 NBA Playoffs
  ?teamSeason wdt:P11176 wd:Q86359233 ;
                wdt:P361 ?team .

  # Find players who played for these teams during 2019-2020 season
  ?player p:P54 [
    ps:P54 ?team ;
    pq:P709 wd:Q63637259
  ] .

  # Ensure they were rookies in 2019-2020
  ?player wdt:P3049 wd:Q63637259 .

  # Get English labels
  OPTIONAL { 
    ?player rdfs:label ?playerLabel .
    FILTER(lang(?playerLabel) = 'en')
  }
}
ORDER BY ?playerLabel

